def text_of_element(element) -> str:
    return "".join(node.text or "" for node in element.xpath(".//w:t"))


def replace_paragraph_text(paragraph, new_text: str) -> None:
    if paragraph.runs:
        paragraph.runs[0].text = new_text
        for run in paragraph.runs[1:]:
            run.text = ""
    else:
        paragraph.add_run(new_text)


def apply_front_matter_replacements(doc: Document) -> None:
    for paragraph in doc.paragraphs:
        text = paragraph.text
        new_text = text
        for source, target in REPLACEMENTS.items():
            new_text = new_text.replace(source, target)
        if new_text != text:
            replace_paragraph_text(paragraph, new_text)


def delete_paragraph(paragraph) -> None:
    element = paragraph._element
    element.getparent().remove(element)
    paragraph._p = paragraph._element = None


def tighten_title_page(doc: Document) -> None:
    city_index = None
    for index, paragraph in enumerate(doc.paragraphs):
        if paragraph.text.strip() == "\u041d\u043e\u0432\u043e\u0441\u0438\u0431\u0438\u0440\u0441\u043a, 2026 \u0433.":
            city_index = index
            break
    if city_index is None:
        return

    code_index = None
    for index, paragraph in enumerate(doc.paragraphs[:city_index]):
        if "\u043a\u043e\u0434 \u0438 \u043d\u0430\u0438\u043c\u0435\u043d\u043e\u0432\u0430\u043d\u0438\u0435 \u043d\u0430\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u0438\u044f" in paragraph.text:
            code_index = index
    if code_index is None or code_index + 1 >= city_index:
        return

    target = doc.paragraphs[code_index + 1]
    replace_paragraph_text(target, "\u041d\u043e\u0432\u043e\u0441\u0438\u0431\u0438\u0440\u0441\u043a, 2026 \u0433.")
    target.alignment = WD_ALIGN_PARAGRAPH.CENTER
    target.paragraph_format.space_before = Pt(18)
    target.paragraph_format.space_after = Pt(0)

    for paragraph in list(doc.paragraphs[code_index + 2:city_index + 2]):
        delete_paragraph(paragraph)

    seen_ministry = 0
    for paragraph in doc.paragraphs:
        if paragraph.text.strip() == "\u041c\u0418\u041d\u0418\u0421\u0422\u0415\u0420\u0421\u0422\u0412\u041e \u041d\u0410\u0423\u041a\u0418 \u0418 \u0412\u042b\u0421\u0428\u0415\u0413\u041e \u041e\u0411\u0420\u0410\u0417\u041e\u0412\u0410\u041d\u0418\u042f \u0420\u041e\u0421\u0421\u0418\u0419\u0421\u041a\u041e\u0419 \u0424\u0415\u0414\u0415\u0420\u0410\u0426\u0418\u0418":
            seen_ministry += 1
            if seen_ministry == 2:
                paragraph.paragraph_format.page_break_before = True
                break


def remove_from_marker(doc: Document, marker: str) -> None:
    body = doc._body._element
    children = list(body)
    start_index = None
    for index, child in enumerate(children):
        if child.tag == qn("w:p") and text_of_element(child).strip().upper() == marker.upper():
            start_index = index
            break
    if start_index is None:
        raise RuntimeError(f"Marker not found: {marker}")
    for child in children[start_index:]:
        if child.tag != qn("w:sectPr"):
            body.remove(child)


def configure_styles(doc: Document) -> None:
    styles = doc.styles
    normal = styles["Normal"]
    normal.font.name = "Times New Roman"
    normal._element.rPr.rFonts.set(qn("w:eastAsia"), "Times New Roman")
    normal.font.size = Pt(14)
    for name in ("Heading 1", "Heading 2", "Heading 3"):
        if name in styles:
            styles[name].font.name = "Times New Roman"
            styles[name]._element.rPr.rFonts.set(qn("w:eastAsia"), "Times New Roman")
            styles[name].font.size = Pt(14 if name != "Heading 3" else 13)


def format_body(paragraph, first_line: bool = True) -> None:
    paragraph.alignment = WD_ALIGN_PARAGRAPH.JUSTIFY
    paragraph.paragraph_format.space_after = Pt(6)
    paragraph.paragraph_format.line_spacing = 1.15
    if first_line:
        paragraph.paragraph_format.first_line_indent = Cm(1.25)


def add_center(doc: Document, text: str, bold: bool = True) -> None:
    paragraph = doc.add_paragraph()
    paragraph.alignment = WD_ALIGN_PARAGRAPH.CENTER
    run = paragraph.add_run(text)
    run.bold = bold
    run.font.name = "Times New Roman"
    run._element.rPr.rFonts.set(qn("w:eastAsia"), "Times New Roman")
    run.font.size = Pt(14)


def add_p(doc: Document, text: str, style: str = "Normal", first_line: bool = True):
    paragraph = doc.add_paragraph(text, style=style)
    format_body(paragraph, first_line=first_line)
    return paragraph


def add_list(doc: Document, items: list[str]) -> None:
    for item in items:
        paragraph = doc.add_paragraph(item, style="List Paragraph")
        paragraph.paragraph_format.left_indent = Cm(1.25)
        paragraph.paragraph_format.first_line_indent = Cm(0)
        paragraph.paragraph_format.space_after = Pt(3)


def add_heading(doc: Document, text: str, level: int = 1) -> None:
    paragraph = doc.add_paragraph(text, style=f"Heading {level}")
    paragraph.paragraph_format.space_before = Pt(12 if level == 1 else 6)
    paragraph.paragraph_format.space_after = Pt(6)


def add_metrics_table(doc: Document) -> None:
    rows = []
    with METRICS.open(encoding="utf-8", newline="") as file:
        for row in csv.DictReader(file):
            rows.append(row)
    table = doc.add_table(rows=1, cols=7)
    table.style = "Table Grid"
    headers = [
        "\u0421\u0446\u0435\u043d\u0430\u0440\u0438\u0439",
        "\u041c\u0430\u043a\u0441. \u043f\u043b\u043e\u0442\u043d., PCU/\u043a\u043c",
        "\u0421\u0440. \u043f\u043b\u043e\u0442\u043d., PCU/\u043a\u043c",
        "\u041f\u043b\u043e\u0442\u043d. \u043d\u0430 \u0443\u0447., PCU/\u043a\u043c",
        "\u041c\u0430\u043a\u0441. \u043f\u043e\u0442\u043e\u043a, PCU/\u0447",
        "\u041e\u0447\u0435\u0440\u0435\u0434\u044c, PCU",
        "\u041e\u0448\u0438\u0431\u043a\u0430 \u0431\u0430\u043b\u0430\u043d\u0441\u0430",
    ]
    for cell, header in zip(table.rows[0].cells, headers):
        cell.text = header
    names = {
        "baseline": "\u0411\u0430\u0437\u043e\u0432\u044b\u0439",
        "lane_blockage": "\u0411\u043b\u043e\u043a\u0438\u0440\u043e\u0432\u043a\u0430 \u043f\u043e\u043b\u043e\u0441\u044b",
        "severe_bottleneck": "\u0421\u0438\u043b\u044c\u043d\u043e\u0435 \u0441\u0443\u0436\u0435\u043d\u0438\u0435",
    }
    for row in rows:
        cells = table.add_row().cells
        values = [
            names.get(row["scenario_name"], row["scenario_name"]),
            f'{float(row["max_density_pcu_km"]):.1f}',
            f'{float(row["avg_density_pcu_km"]):.1f}',
            f'{float(row["incident_link_max_density_pcu_km"]):.1f}',
            f'{float(row["max_flow_pcu_h"]):.1f}',
            f'{float(row["max_source_queue_pcu"]):.1f}',
            f'{float(row["conservation_error_pcu"]):.2e}',
        ]
        for cell, value in zip(cells, values):
            cell.text = value
    doc.add_paragraph("\u0422\u0430\u0431\u043b\u0438\u0446\u0430 1 - \u0421\u0432\u043e\u0434\u043d\u044b\u0435 \u043f\u043e\u043a\u0430\u0437\u0430\u0442\u0435\u043b\u0438 CTM-\u044d\u043a\u0441\u043f\u0435\u0440\u0438\u043c\u0435\u043d\u0442\u043e\u0432")


def add_picture(doc: Document, path: Path, caption: str) -> None:
    if not path.exists():
        return
    paragraph = doc.add_paragraph()
    paragraph.alignment = WD_ALIGN_PARAGRAPH.CENTER
    paragraph.add_run().add_picture(str(path), width=Cm(15.0))
    caption_p = doc.add_paragraph(caption)
    caption_p.alignment = WD_ALIGN_PARAGRAPH.CENTER
    caption_p.paragraph_format.space_after = Pt(8)


def add_code_excerpt(doc: Document, path: Path, title: str, limit: int = 90) -> None:
    add_heading(doc, title, 2)
    lines = path.read_text(encoding="utf-8", errors="replace").splitlines()
    kept = []
    for line in lines:
        if "\u0420" in line and "\u0421" in line:
            continue
        kept.append(line.rstrip())
        if len(kept) >= limit:
            break
    for line in kept:
        paragraph = doc.add_paragraph()
        paragraph.paragraph_format.space_after = Pt(0)
        paragraph.paragraph_format.line_spacing = 1.0
        run = paragraph.add_run(line if line else " ")
        run.font.name = "Consolas"
        run._element.rPr.rFonts.set(qn("w:eastAsia"), "Consolas")
        run.font.size = Pt(8)


