    add_p(doc, "\u0414\u0430\u043d\u043d\u044b\u0435 OpenStreetMap \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u044e\u0442\u0441\u044f \u043a\u0430\u043a \u0438\u0441\u0445\u043e\u0434\u043d\u0430\u044f \u0433\u0435\u043e\u043c\u0435\u0442\u0440\u0438\u044f. \u0418\u043c\u043f\u043e\u0440\u0442\u0435\u0440 \u0432\u044b\u0434\u0435\u043b\u044f\u0435\u0442 \u0434\u043e\u0440\u043e\u0433\u0438 \u0437\u0430\u0434\u0430\u043d\u043d\u044b\u0445 \u043a\u043b\u0430\u0441\u0441\u043e\u0432, \u0441\u0442\u0440\u043e\u0438\u0442 \u043d\u0430\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u043d\u044b\u0435 \u0437\u0432\u0435\u043d\u044c\u044f, \u0443\u0447\u0438\u0442\u044b\u0432\u0430\u0435\u0442 \u0447\u0438\u0441\u043b\u043e \u043f\u043e\u043b\u043e\u0441 \u0438 \u0443\u043f\u0440\u043e\u0449\u0430\u0435\u0442 \u0433\u0435\u043e\u043c\u0435\u0442\u0440\u0438\u044e. \u041f\u043e\u0441\u043b\u0435 \u0438\u043c\u043f\u043e\u0440\u0442\u0430 \u0441\u0435\u0442\u044c \u0441\u043e\u0445\u0440\u0430\u043d\u044f\u0435\u0442\u0441\u044f \u0432 JSON-\u043f\u0440\u043e\u0435\u043a\u0442\u0435 \u0438 \u043c\u043e\u0436\u0435\u0442 \u043f\u043e\u0432\u0442\u043e\u0440\u043d\u043e \u0437\u0430\u0433\u0440\u0443\u0436\u0430\u0442\u044c\u0441\u044f \u0434\u043b\u044f \u0440\u0430\u0441\u0447\u0435\u0442\u043e\u0432.")

