    add_p(doc, "\u041f\u0440\u043e\u0433\u0440\u0430\u043c\u043c\u0430 \u0440\u0430\u0437\u0434\u0435\u043b\u0435\u043d\u0430 \u043d\u0430 \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0438\u0445 \u0431\u043b\u043e\u043a\u043e\u0432. \u0411\u0430\u0437\u043e\u0432\u044b\u0435 \u0441\u0443\u0449\u043d\u043e\u0441\u0442\u0438 Node, Link, Route, Network \u0438 Project \u043e\u043f\u0438\u0441\u0430\u043d\u044b \u0432 models.py. \u0417\u0430\u0433\u0440\u0443\u0437\u043a\u0430 \u0438 \u0441\u043e\u0445\u0440\u0430\u043d\u0435\u043d\u0438\u0435 JSON-\u043f\u0440\u043e\u0435\u043a\u0442\u043e\u0432 \u0432\u044b\u043d\u0435\u0441\u0435\u043d\u044b \u0432 project_loader.py \u0438 project_saver.py.")
    add_p(doc, "osm_project_importer.py \u043f\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u0435\u0442 OSM-\u0434\u0430\u043d\u043d\u044b\u0435 \u0432 \u0433\u0440\u0430\u0444 \u0441\u0435\u0442\u0438. ctm_network_core.py \u0441\u043e\u0434\u0435\u0440\u0436\u0438\u0442 \u044f\u0434\u0440\u043e \u043e\u0434\u043d\u043e\u0433\u043e CTM-\u0437\u0432\u0435\u043d\u0430: \u044f\u0447\u0435\u0439\u043a\u0438, \u0438\u043d\u0446\u0438\u0434\u0435\u043d\u0442\u044b, \u043f\u043e\u0442\u043e\u043a\u0438 \u0438 \u043f\u0440\u043e\u0432\u0435\u0440\u043a\u0438 \u043a\u043e\u0440\u0440\u0435\u043a\u0442\u043d\u043e\u0441\u0442\u0438. ctm_node_solver.py \u0440\u0435\u0448\u0430\u0435\u0442 \u043f\u043e\u0442\u043e\u043a\u0438 \u0447\u0435\u0440\u0435\u0437 \u0443\u0437\u043b\u044b. ctm_network_simulator.py \u043e\u0431\u044a\u0435\u0434\u0438\u043d\u044f\u0435\u0442 \u044d\u0442\u0438 \u0431\u043b\u043e\u043a\u0438 \u0432 \u0441\u0435\u0442\u0435\u0432\u0443\u044e \u0441\u0438\u043c\u0443\u043b\u044f\u0446\u0438\u044e.")
    add_p(doc, "ctm_experiment_runner.py \u0437\u0430\u0434\u0430\u0435\u0442 \u043d\u0430\u0431\u043e\u0440 \u0441\u0446\u0435\u043d\u0430\u0440\u0438\u0435\u0432, \u0437\u0430\u043f\u0443\u0441\u043a\u0430\u0435\u0442 \u0440\u0430\u0441\u0447\u0435\u0442\u044b, \u0444\u043e\u0440\u043c\u0438\u0440\u0443\u0435\u0442 CSV-\u0442\u0430\u0431\u043b\u0438\u0446\u044b \u0438 PNG-\u0433\u0440\u0430\u0444\u0438\u043a\u0438. traffic_viz_test.py \u0438 network_editor.py \u043e\u0442\u0432\u0435\u0447\u0430\u044e\u0442 \u0437\u0430 \u0432\u0438\u0437\u0443\u0430\u043b\u044c\u043d\u0443\u044e \u0447\u0430\u0441\u0442\u044c: \u043e\u0442\u0440\u0438\u0441\u043e\u0432\u043a\u0443 \u0441\u0435\u0442\u0438, \u0443\u0437\u043b\u043e\u0432, \u0441\u0442\u0440\u0435\u043b\u043e\u043a \u043d\u0430\u043f\u0440\u0430\u0432\u043b\u0435\u043d\u0438\u044f \u0438 \u043f\u0430\u0440\u0430\u043c\u0435\u0442\u0440\u043e\u0432 \u0437\u0432\u0435\u043d\u044c\u0435\u0432.")
