    add_p(doc, "\u0411\u0430\u0437\u043e\u0432\u044b\u0439 \u0441\u0446\u0435\u043d\u0430\u0440\u0438\u0439 \u043d\u0435 \u0441\u043e\u0437\u0434\u0430\u0435\u0442 \u0432\u043d\u0435\u0448\u043d\u0435\u0439 \u043e\u0447\u0435\u0440\u0435\u0434\u0438 \u0438 \u043e\u0441\u0442\u0430\u0435\u0442\u0441\u044f \u0442\u043e\u0447\u043a\u043e\u0439 \u0441\u0440\u0430\u0432\u043d\u0435\u043d\u0438\u044f. \u041f\u0440\u0438 \u0431\u043b\u043e\u043a\u0438\u0440\u043e\u0432\u043a\u0435 \u043f\u043e\u043b\u043e\u0441\u044b \u043c\u0430\u043a\u0441\u0438\u043c\u0430\u043b\u044c\u043d\u0430\u044f \u043f\u043b\u043e\u0442\u043d\u043e\u0441\u0442\u044c \u043d\u0430 \u0438\u0441\u0441\u043b\u0435\u0434\u0443\u0435\u043c\u043e\u043c \u0443\u0447\u0430\u0441\u0442\u043a\u0435 \u0434\u043e\u0441\u0442\u0438\u0433\u0430\u0435\u0442 165 PCU/\u043a\u043c, \u0430 \u043f\u0440\u0438 \u0441\u0438\u043b\u044c\u043d\u043e\u043c \u0441\u0443\u0436\u0435\u043d\u0438\u0438 - 199,5 PCU/\u043a\u043c. \u041f\u0440\u0438 \u044d\u0442\u043e\u043c \u043e\u0448\u0438\u0431\u043a\u0430 \u0431\u0430\u043b\u0430\u043d\u0441\u0430 \u043e\u0441\u0442\u0430\u0435\u0442\u0441\u044f \u043d\u0430 \u0447\u0438\u0441\u043b\u0435\u043d\u043d\u043e \u043c\u0430\u043b\u043e\u043c \u0443\u0440\u043e\u0432\u043d\u0435.")
